export { default as SLink } from './link.vue';

export type { LinkBaseProps, LinkExtraProps } from '@soybeanjs/headless/link';
export type * from './types';

import type { LinkProps as _LinkProps } from '@soybeanjs/headless/link';
import type { ClassValue } from '@soybeanjs/headless/types';

/**
 * Properties for the Link component.
 */
export interface LinkProps extends _LinkProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
}

// @unocss-include
import { cv } from '@soybeanjs/cva';

export const linkVariants = cv({
  base: 'outline-none cursor-pointer decoration-none data-[disabled]:cursor-not-allowed data-[disabled]:opacity-50'
});
